SELECT o.orderid, od.quantity, od.unitprice FROM orders AS o JOIN "order details" AS od ON o.orderid = od.orderid JOIN products AS p ON od.productid = p.productid JOIN categories AS c ON p.categoryid = c.categoryid LEFT JOIN region AS r ON o.shipregion = r.regionid WHERE (c.categoryname = 'Confections') AND (r.regiondescription = 'Eastern' OR r.regiondescription IS NULL) AND (strftime('%Y', o.shippeddate) = '1997')
